import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  Button,
  Grid,
  TextField,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  IconButton,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  Alert,
  Card,
  CardContent,
  Divider,
  Chip,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  CircularProgress,
  Autocomplete,
} from '@mui/material';
import {
  Add,
  Delete,
  Save,
  Cancel,
  ShoppingCart,
  Search,
  Person,
  Inventory,
  Receipt,
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { salesService } from '../../services/salesService';
import { customerService } from '../../services/customerService';
import { itemService } from '../../services/itemService';

const SalesEntry = () => {
  const [invoice, setInvoice] = useState({
    invoiceDate: new Date().toISOString().split('T')[0],
    customerId: '',
    customer: null,
    paymentType: 'CASH',
    items: [],
    notes: '',
  });
  const [customers, setCustomers] = useState([]);
  const [items, setItems] = useState([]);
  const [selectedItem, setSelectedItem] = useState(null);
  const [quantity, setQuantity] = useState(1);
  const [loading, setLoading] = useState(false);
  const [loadingData, setLoadingData] = useState(true);
  const [error, setError] = useState('');
  const [customerSearch, setCustomerSearch] = useState('');
  const [itemSearch, setItemSearch] = useState('');

  useEffect(() => {
    fetchInitialData();
  }, []);

  const fetchInitialData = async () => {
    setLoadingData(true);
    try {
      console.log('🔄 Fetching customers and items...');
      
      // Fetch customers
      const customersData = await customerService.getAll(0, 1000);
      setCustomers(customersData.content || []);
      console.log('✅ Customers loaded:', customersData.content?.length || 0);
      
      // Fetch items
      const itemsData = await itemService.getAll(0, 1000);
      setItems(itemsData.content || []);
      console.log('✅ Items loaded:', itemsData.content?.length || 0);
      
    } catch (error) {
      console.error('❌ Error fetching data:', error);
      toast.error('Failed to load customers or items');
    } finally {
      setLoadingData(false);
    }
  };

  const handleCustomerSelect = (event, value) => {
    if (value) {
      setInvoice({
        ...invoice,
        customerId: value.id,
        customer: value,
      });
    } else {
      setInvoice({
        ...invoice,
        customerId: '',
        customer: null,
      });
    }
  };

  const handleAddItem = () => {
    if (!selectedItem) {
      toast.warning('Please select an item');
      return;
    }

    // Check if item already exists in the invoice
    const existingItem = invoice.items.find(
      (item) => item.itemId === selectedItem.id
    );

    if (existingItem) {
      toast.warning('Item already added to invoice');
      return;
    }

    // Check stock availability
    if (selectedItem.currentStock < quantity) {
      toast.error(`Insufficient stock! Available: ${selectedItem.currentStock}`);
      return;
    }

    const newItem = {
      itemId: selectedItem.id,
      itemName: selectedItem.name,
      itemCode: selectedItem.code,
      quantity: quantity,
      unitPrice: selectedItem.sellingPrice,
      discountPercent: 0,
      taxPercent: selectedItem.gstRate || 0,
      totalAmount: quantity * selectedItem.sellingPrice,
    };

    setInvoice({
      ...invoice,
      items: [...invoice.items, newItem],
    });

    setSelectedItem(null);
    setQuantity(1);
    setItemSearch('');
    toast.success('Item added to invoice');
  };

  const handleRemoveItem = (index) => {
    const updatedItems = invoice.items.filter((_, i) => i !== index);
    setInvoice({ ...invoice, items: updatedItems });
  };

  const handleItemQuantityChange = (index, value) => {
    const updatedItems = [...invoice.items];
    const qty = parseFloat(value) || 0;
    const item = items.find(i => i.id === updatedItems[index].itemId);
    
    if (item && qty > item.currentStock) {
      toast.error(`Insufficient stock! Available: ${item.currentStock}`);
      return;
    }
    
    updatedItems[index].quantity = qty;
    updatedItems[index].totalAmount = qty * updatedItems[index].unitPrice;
    setInvoice({ ...invoice, items: updatedItems });
  };

  const calculateTotals = () => {
    let total = 0;
    let totalDiscount = 0;
    let totalTax = 0;

    invoice.items.forEach((item) => {
      const lineTotal = item.quantity * item.unitPrice;
      const discount = lineTotal * (item.discountPercent / 100);
      const tax = (lineTotal - discount) * (item.taxPercent / 100);
      total += lineTotal;
      totalDiscount += discount;
      totalTax += tax;
    });

    return {
      totalAmount: total,
      totalDiscount: totalDiscount,
      totalTax: totalTax,
      netAmount: total - totalDiscount + totalTax,
    };
  };

  const handleSubmit = async () => {
    if (!invoice.customerId) {
      setError('Please select a customer');
      return;
    }

    if (invoice.items.length === 0) {
      setError('Please add at least one item');
      return;
    }

    const totals = calculateTotals();
    const requestData = {
      invoiceDate: invoice.invoiceDate,
      customerId: invoice.customerId,
      paymentType: invoice.paymentType,
      notes: invoice.notes,
      items: invoice.items.map((item) => ({
        itemId: item.itemId,
        quantity: item.quantity,
        unitPrice: item.unitPrice,
        discountPercent: item.discountPercent,
        taxPercent: item.taxPercent,
      })),
    };

    setLoading(true);
    setError('');
    try {
      const response = await salesService.createInvoice(requestData);
      toast.success(`Invoice ${response.invoiceNo} created successfully!`);
      // Reset form
      setInvoice({
        invoiceDate: new Date().toISOString().split('T')[0],
        customerId: '',
        customer: null,
        paymentType: 'CASH',
        items: [],
        notes: '',
      });
      // Refresh items to update stock
      const itemsData = await itemService.getAll(0, 1000);
      setItems(itemsData.content || []);
    } catch (error) {
      console.error('Create invoice error:', error);
      setError(error.response?.data?.error || 'Failed to create invoice');
    } finally {
      setLoading(false);
    }
  };

  const totals = calculateTotals();

  if (loadingData) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="400px">
        <CircularProgress />
        <Typography sx={{ ml: 2 }}>Loading data...</Typography>
      </Box>
    );
  }

  return (
    <Box>
      <Box display="flex" alignItems="center" gap={2} mb={3}>
        <Receipt sx={{ fontSize: 40, color: '#1976d2' }} />
        <Box>
          <Typography variant="h4" fontWeight="bold">
            Sales Entry
          </Typography>
          <Typography variant="body2" color="textSecondary">
            Create a new sales invoice
          </Typography>
        </Box>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError('')}>
          {error}
        </Alert>
      )}

      <Grid container spacing={3}>
        <Grid item xs={12} md={8}>
          <Paper sx={{ p: 3, borderRadius: 2 }}>
            <Typography variant="h6" gutterBottom>
              Invoice Details
            </Typography>

            <Grid container spacing={2}>
              <Grid item xs={12} md={6}>
                <TextField
                  fullWidth
                  label="Invoice Date"
                  type="date"
                  value={invoice.invoiceDate}
                  onChange={(e) =>
                    setInvoice({ ...invoice, invoiceDate: e.target.value })
                  }
                  InputLabelProps={{ shrink: true }}
                />
              </Grid>
              <Grid item xs={12} md={6}>
                <Autocomplete
                  options={customers}
                  getOptionLabel={(option) => `${option.name} (${option.phone})`}
                  value={invoice.customer}
                  onChange={handleCustomerSelect}
                  renderInput={(params) => (
                    <TextField
                      {...params}
                      label="Search Customer"
                      placeholder="Type to search..."
                      InputProps={{
                        ...params.InputProps,
                        startAdornment: (
                          <>
                            <Person sx={{ color: '#1976d2', mr: 1 }} />
                            {params.InputProps.startAdornment}
                          </>
                        ),
                      }}
                    />
                  )}
                  isOptionEqualToValue={(option, value) => option.id === value?.id}
                  noOptionsText="No customers found"
                  loading={loadingData}
                />
              </Grid>
              <Grid item xs={12}>
                <FormControl fullWidth>
                  <InputLabel>Payment Type</InputLabel>
                  <Select
                    value={invoice.paymentType}
                    onChange={(e) =>
                      setInvoice({ ...invoice, paymentType: e.target.value })
                    }
                    label="Payment Type"
                  >
                    <MenuItem value="CASH">Cash</MenuItem>
                    <MenuItem value="CREDIT">Credit</MenuItem>
                  </Select>
                </FormControl>
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="Notes"
                  multiline
                  rows={2}
                  value={invoice.notes}
                  onChange={(e) =>
                    setInvoice({ ...invoice, notes: e.target.value })
                  }
                />
              </Grid>
            </Grid>

            <Divider sx={{ my: 3 }} />

            <Typography variant="h6" gutterBottom>
              Items
            </Typography>

            <Box display="flex" gap={2} mb={2} flexWrap="wrap">
              <Autocomplete
                options={items}
                getOptionLabel={(option) => `${option.code} - ${option.name} (Stock: ${option.currentStock})`}
                value={selectedItem}
                onChange={(event, value) => {
                  setSelectedItem(value);
                  if (value) {
                    setQuantity(1);
                  }
                }}
                renderInput={(params) => (
                  <TextField
                    {...params}
                    label="Search Item"
                    placeholder="Type to search..."
                    sx={{ flexGrow: 1, minWidth: 250 }}
                    size="small"
                  />
                )}
                isOptionEqualToValue={(option, value) => option.id === value?.id}
                noOptionsText="No items found"
                disabled={loadingData}
              />
              <TextField
                label="Quantity"
                type="number"
                value={quantity}
                onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                sx={{ width: 120 }}
                size="small"
                InputProps={{ inputProps: { min: 1 } }}
              />
              <Button
                variant="contained"
                startIcon={<Add />}
                onClick={handleAddItem}
                disabled={!selectedItem}
              >
                Add
              </Button>
            </Box>

            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow sx={{ backgroundColor: '#f5f7fa' }}>
                    <TableCell>Item</TableCell>
                    <TableCell>Code</TableCell>
                    <TableCell align="right">Qty</TableCell>
                    <TableCell align="right">Rate</TableCell>
                    <TableCell align="right">Discount</TableCell>
                    <TableCell align="right">Tax</TableCell>
                    <TableCell align="right">Total</TableCell>
                    <TableCell align="center">Action</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {invoice.items.length === 0 ? (
                    <TableRow>
                      <TableCell colSpan={8} align="center" sx={{ py: 3 }}>
                        <Typography color="textSecondary">
                          No items added yet. Please add items to the invoice.
                        </Typography>
                      </TableCell>
                    </TableRow>
                  ) : (
                    invoice.items.map((item, index) => (
                      <TableRow key={index}>
                        <TableCell>{item.itemName}</TableCell>
                        <TableCell>{item.itemCode}</TableCell>
                        <TableCell align="right">
                          <TextField
                            type="number"
                            size="small"
                            value={item.quantity}
                            onChange={(e) => handleItemQuantityChange(index, e.target.value)}
                            sx={{ width: 80 }}
                            InputProps={{ inputProps: { min: 1 } }}
                          />
                        </TableCell>
                        <TableCell align="right">₹{item.unitPrice.toFixed(2)}</TableCell>
                        <TableCell align="right">
                          <TextField
                            type="number"
                            size="small"
                            value={item.discountPercent}
                            onChange={(e) => {
                              const updatedItems = [...invoice.items];
                              updatedItems[index].discountPercent = parseFloat(e.target.value) || 0;
                              updatedItems[index].totalAmount = 
                                updatedItems[index].quantity * updatedItems[index].unitPrice * 
                                (1 - updatedItems[index].discountPercent / 100) * 
                                (1 + updatedItems[index].taxPercent / 100);
                              setInvoice({ ...invoice, items: updatedItems });
                            }}
                            sx={{ width: 70 }}
                            InputProps={{ endAdornment: '%' }}
                          />
                        </TableCell>
                        <TableCell align="right">
                          {item.taxPercent}%
                        </TableCell>
                        <TableCell align="right">
                          ₹{item.totalAmount.toFixed(2)}
                        </TableCell>
                        <TableCell align="center">
                          <IconButton
                            size="small"
                            color="error"
                            onClick={() => handleRemoveItem(index)}
                          >
                            <Delete />
                          </IconButton>
                        </TableCell>
                      </TableRow>
                    ))
                  )}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        </Grid>

        <Grid item xs={12} md={4}>
          <Card sx={{ borderRadius: 2, position: 'sticky', top: 20 }}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Invoice Summary
              </Typography>

              <Box sx={{ mt: 2 }}>
                <Box display="flex" justifyContent="space-between" py={1}>
                  <Typography color="textSecondary">Total Items</Typography>
                  <Typography fontWeight={500}>{invoice.items.length}</Typography>
                </Box>
                <Divider />
                <Box display="flex" justifyContent="space-between" py={1}>
                  <Typography color="textSecondary">Total Amount</Typography>
                  <Typography fontWeight={500}>
                    ₹{totals.totalAmount.toFixed(2)}
                  </Typography>
                </Box>
                <Box display="flex" justifyContent="space-between" py={1}>
                  <Typography color="textSecondary">Total Discount</Typography>
                  <Typography color="success.main" fontWeight={500}>
                    -₹{totals.totalDiscount.toFixed(2)}
                  </Typography>
                </Box>
                <Box display="flex" justifyContent="space-between" py={1}>
                  <Typography color="textSecondary">Total Tax</Typography>
                  <Typography fontWeight={500}>
                    +₹{totals.totalTax.toFixed(2)}
                  </Typography>
                </Box>
                <Divider sx={{ my: 1 }} />
                <Box display="flex" justifyContent="space-between" py={1}>
                  <Typography variant="h6">Net Amount</Typography>
                  <Typography variant="h6" color="primary">
                    ₹{totals.netAmount.toFixed(2)}
                  </Typography>
                </Box>
              </Box>

              <Box mt={3}>
                <Button
                  fullWidth
                  variant="contained"
                  size="large"
                  startIcon={<Save />}
                  onClick={handleSubmit}
                  disabled={loading || invoice.items.length === 0}
                  sx={{ mb: 1 }}
                >
                  {loading ? 'Creating...' : 'Create Invoice'}
                </Button>
                <Button
                  fullWidth
                  variant="outlined"
                  startIcon={<Cancel />}
                  onClick={() => {
                    setInvoice({
                      invoiceDate: new Date().toISOString().split('T')[0],
                      customerId: '',
                      customer: null,
                      paymentType: 'CASH',
                      items: [],
                      notes: '',
                    });
                    setError('');
                  }}
                >
                  Reset
                </Button>
              </Box>

              {invoice.customer && (
                <Box mt={2} p={2} bgcolor="#f5f7fa" borderRadius={1}>
                  <Typography variant="subtitle2" gutterBottom>
                    Customer Details
                  </Typography>
                  <Typography variant="body2">
                    <strong>Name:</strong> {invoice.customer.name}
                  </Typography>
                  <Typography variant="body2">
                    <strong>Phone:</strong> {invoice.customer.phone}
                  </Typography>
                  {invoice.customer.creditLimit > 0 && (
                    <Typography variant="body2">
                      <strong>Credit Limit:</strong> ₹{invoice.customer.creditLimit}
                    </Typography>
                  )}
                  <Typography variant="body2">
                    <strong>Credit Balance:</strong> ₹{invoice.customer.creditBalance || 0}
                  </Typography>
                </Box>
              )}
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default SalesEntry;
